#!/usr/bin/env bun
// Integration test harness: runs the workflow through act and validates output
// This ensures the actual CI/CD pipeline works correctly

import { execSync } from "child_process";
import { writeFileSync, existsSync } from "fs";
import { resolve } from "path";

interface TestCase {
  name: string;
  expectedPasses: number;
  expectedMatrixSize?: number;
  shouldFail?: boolean;
}

const testCases: TestCase[] = [
  {
    name: "Test 1: Unit Tests Pass",
    expectedPasses: 10,
  },
  {
    name: "Test 2: Basic Matrix Generation",
    expectedMatrixSize: 4,
  },
  {
    name: "Test 3: Advanced Matrix Features",
    expectedMatrixSize: 3,
  },
  {
    name: "Test 4: Include Rules",
    expectedMatrixSize: 2,
  },
];

async function runActPipeline(): Promise<string> {
  console.log("🚀 Starting GitHub Actions workflow via act...\n");

  try {
    // Run act with push trigger
    const cmd = `act push --rm --verbose 2>&1`;
    const output = execSync(cmd, {
      cwd: process.cwd(),
      encoding: "utf-8",
      maxBuffer: 50 * 1024 * 1024, // 50MB buffer for large outputs
    });

    return output;
  } catch (error: unknown) {
    if (error instanceof Error) {
      const message = error.message || String(error);
      // act might exit with code 1 even on success in some scenarios
      if (message.includes("exit status") || message.includes("Process exited")) {
        // Try to extract output from error
        return message;
      }
    }
    throw error;
  }
}

async function validateActOutput(output: string): Promise<void> {
  const results: {
    passed: number;
    failed: number;
    errors: string[];
  } = {
    passed: 0,
    failed: 0,
    errors: [],
  };

  console.log("📋 Validating act output...\n");

  // Check for successful job completion
  if (output.includes("Job succeeded")) {
    console.log("✓ Job completion detected");
    results.passed++;
  } else if (output.includes("FAILED") || output.includes("failed")) {
    console.log("✗ Job failed");
    results.failed++;
    results.errors.push("Job did not complete successfully");
  }

  // Check for unit test pass
  if (output.includes("10 pass")) {
    console.log("✓ 10 unit tests passed");
    results.passed++;
  } else if (output.includes("pass")) {
    const match = output.match(/(\d+)\s+pass/);
    if (match) {
      const count = parseInt(match[1]);
      if (count >= 10) {
        console.log(`✓ ${count} unit tests passed`);
        results.passed++;
      } else {
        console.log(`✗ Only ${count} tests passed (expected 10)`);
        results.failed++;
      }
    }
  } else {
    console.log("✗ Could not find test pass information");
    results.failed++;
  }

